{
  "incident_meta": {
    "incident_id": "INC-2026-04-08-001",
    "title": "Database Connection Pool Exhaustion",
    "severity": "P3 - Minor",
    "status": "resolved",
    "created_at": "2026-04-08T14:45:00+08:00"
  },
  "timeline": {
    "incident_start": "2026-04-08T14:00:00+08:00",
    "incident_end": "2026-04-08T14:45:00+08:00",
    "detection_time": "2026-04-08T14:02:00+08:00",
    "resolution_time": "2026-04-08T14:45:00+08:00",
    "total_duration_minutes": 45
  },
  "events": [
    {
      "timestamp": "2026-04-08T14:00:00+08:00",
      "type": "start",
      "actor": "system",
      "description": "Database connection pool saturation begins due to unexpected traffic spike"
    },
    {
      "timestamp": "2026-04-08T14:02:00+08:00",
      "type": "detection",
      "actor": "monitoring_system",
      "description": "PagerDuty alert triggered: API error rate exceeded 5% threshold"
    },
    {
      "timestamp": "2026-04-08T14:03:00+08:00",
      "type": "acknowledge",
      "actor": "oncall_engineer",
      "description": "On-call engineer acknowledged the alert and began investigation"
    },
    {
      "timestamp": "2026-04-08T14:08:00+08:00",
      "type": "diagnosis",
      "actor": "oncall_engineer",
      "description": "Identified root cause: primary database connection pool exhausted (max 100 connections)"
    },
    {
      "timestamp": "2026-04-08T14:10:00+08:00",
      "type": "action",
      "actor": "oncall_engineer",
      "description": "Initiated emergency connection pool scaling from 100 to 200 connections"
    },
    {
      "timestamp": "2026-04-08T14:15:00+08:00",
      "type": "action",
      "actor": "oncall_engineer",
      "description": "Enabled query result caching to reduce database load"
    },
    {
      "timestamp": "2026-04-08T14:20:00+08:00",
      "type": "mitigation",
      "actor": "system",
      "description": "Traffic spike subsided; connection pool utilization normalized to 60%"
    },
    {
      "timestamp": "2026-04-08T14:25:00+08:00",
      "type": "action",
      "actor": "oncall_engineer",
      "description": "Increased connection pool size permanently to 150 to provide headroom"
    },
    {
      "timestamp": "2026-04-08T14:30:00+08:00",
      "type": "verification",
      "actor": "oncall_engineer",
      "description": "Verified all systems operational; error rate returned to 0.4%"
    },
    {
      "timestamp": "2026-04-08T14:45:00+08:00",
      "type": "resolution",
      "actor": "oncall_engineer",
      "description": "Incident marked as resolved; post-mortem scheduled for following day"
    }
  ],
  "impact": {
    "affected_services": ["api_gateway", "user_service", "project_service"],
    "error_rate_peak": 8.5,
    "affected_requests": 4520,
    "user_impact": "Degraded response times for 5% of users; 0.5% of requests failed"
  },
  "post_incident_actions": [
    "Implement automatic connection pool scaling based on traffic patterns",
    "Add proactive alerting for connection pool utilization > 80%",
    "Review database query optimization opportunities"
  ]
}

